// Dynamic feed builder — reads editorial themes from pipeline_search_config
// v2: includes topic volume tracking for trend scoring

const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

const DEFAULT_TAGS = [
  { tag: 'inteligência artificial', topic: 'ia' },
  { tag: 'cibersegurança', topic: 'ciberseguranca' },
  { tag: 'automação empresarial', topic: 'automacao' },
];

function buildGoogleNewsUrl(query) {
  return 'https://news.google.com/rss/search?q=' + encodeURIComponent(query) + '&hl=pt-PT&gl=PT&ceid=PT:pt';
}

function tagToTopic(tag) {
  return tag.toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '').replace(/[^a-z0-9]+/g, '_').replace(/^_|_$/g, '');
}

function isMissingEditorialColumns(message) {
  return /(default_post_tags|theme_rules)/i.test(String(message || '')) && /(does not exist|schema cache|Could not find)/i.test(String(message || ''));
}

async function loadPipelineConfig() {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/pipeline_search_config?is_active=eq.true&limit=1&select=tags,theme_rules',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' },
    });
    const configs = Array.isArray(resp) ? resp : [];
    return configs[0] || null;
  } catch (e) {
    if (!isMissingEditorialColumns(e?.message)) throw e;
    const legacyResp = await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/pipeline_search_config?is_active=eq.true&limit=1&select=tags',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' },
    });
    const legacyConfigs = Array.isArray(legacyResp) ? legacyResp : [];
    return legacyConfigs[0] || null;
  }
}

// Load recent staging counts per topic (last 24h) to detect velocity
async function loadRecentVolume() {
  try {
    const since = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/news_staging?select=topic,id&collected_at=gte.' + since,
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY },
    });
    const rows = Array.isArray(resp) ? resp : [];
    const counts = {};
    for (const r of rows) {
      const t = r.topic || 'geral';
      counts[t] = (counts[t] || 0) + 1;
    }
    return counts;
  } catch (e) {
    return {};
  }
}

let tags = DEFAULT_TAGS;

try {
  const activeConfig = await loadPipelineConfig();
  const themeRules = Array.isArray(activeConfig?.theme_rules) ? activeConfig.theme_rules : [];

  if (themeRules.length > 0) {
    const themedTags = themeRules.flatMap((rule) => {
      const searchTerms = Array.isArray(rule?.searchTerms) ? rule.searchTerms : Array.isArray(rule?.search_terms) ? rule.search_terms : [];
      const slug = String(rule?.slug || '').trim();
      return searchTerms.map((term) => String(term || '').trim()).filter(Boolean).map((term) => ({ tag: term, topic: slug || tagToTopic(term) }));
    });
    if (themedTags.length > 0) tags = themedTags;
  } else if (Array.isArray(activeConfig?.tags) && activeConfig.tags.length > 0) {
    tags = activeConfig.tags.map((t) => ({ tag: t, topic: tagToTopic(t) }));
  }
} catch (e) { /* fallback to defaults */ }

const volumeByTopic = await loadRecentVolume.call(this);

return tags.map((t) => ({
  json: {
    url: buildGoogleNewsUrl(t.tag),
    topic: t.topic,
    search_tag: t.tag,
    recent_volume: volumeByTopic[t.topic] || 0
  }
}));

// Parse RSS XML into structured items
const feedUrl = $('Build Feed List').item.json.url;
const topic = $('Build Feed List').item.json.topic;
const searchTag = $('Build Feed List').item.json.search_tag;
const recentVolume = $('Build Feed List').item.json.recent_volume || 0;

const xml = String($input.first().json.data || '');
if (!xml || !xml.includes('<item>')) {
  // No RSS items — return empty to skip downstream
  return [];
}

const itemBlocks = xml.split('<item>').slice(1);
const output = [];

function extractTag(block, tag) {
  const regex = new RegExp('<' + tag + '[^>]*><!\\[CDATA\\\\[(.+?)\\]\\]>|<' + tag + '[^>]*>([^<]*)</' + tag + '>', 's');
  const m = block.match(regex);
  return (m ? (m[1] || m[2] || '') : '').trim();
}

for (const block of itemBlocks) {
  try {
    const title = extractTag(block, 'title');
    const link = extractTag(block, 'link');
    const pubDate = extractTag(block, 'pubDate');
    const description = extractTag(block, 'description');
    const source = extractTag(block, 'source');
    if (!title || !link) continue;

    let isoDate;
    try { isoDate = new Date(pubDate).toISOString(); } catch { isoDate = new Date().toISOString(); }

    output.push({
      json: {
        title,
        link,
        isoDate,
        pubDate,
        contentSnippet: description.replace(/<[^>]+>/g, '').substring(0, 500),
        content: description,
        source: source || 'Google News',
        creator: source || 'Google News',
        _feedUrl: feedUrl,
        _topic: topic,
        _searchTag: searchTag,
        _recentVolume: recentVolume
      }
    });
  } catch (e) { /* skip malformed item */ }
}

return output;

function fnv1aHash(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  h = h >>> 0;
  let hex = h.toString(16).padStart(8, '0');
  let h2 = 0x811c9dc5;
  for (let i = str.length - 1; i >= 0; i--) {
    h2 ^= str.charCodeAt(i);
    h2 = Math.imul(h2, 0x01000193);
  }
  h2 = h2 >>> 0;
  hex += h2.toString(16).padStart(8, '0');
  let h3 = 0x811c9dc5;
  for (let i = 0; i < str.length; i += 2) {
    h3 ^= str.charCodeAt(i);
    h3 = Math.imul(h3, 0x01000193);
  }
  h3 = h3 >>> 0;
  hex += h3.toString(16).padStart(8, '0');
  let h4 = 0x811c9dc5;
  for (let i = 1; i < str.length; i += 2) {
    h4 ^= str.charCodeAt(i);
    h4 = Math.imul(h4, 0x01000193);
  }
  h4 = h4 >>> 0;
  hex += h4.toString(16).padStart(8, '0');
  return hex;
}

// Estimate trend score based on recency and volume signals
function calculateTrendScore(item, feedMeta) {
  let score = 50; // baseline

  // Recency bonus: articles < 2h get +30, < 6h get +20, < 12h get +10
  const pubDate = new Date(item.json.isoDate || item.json.pubDate || Date.now());
  const hoursAgo = (Date.now() - pubDate.getTime()) / (1000 * 60 * 60);
  if (hoursAgo < 2) score += 30;
  else if (hoursAgo < 6) score += 20;
  else if (hoursAgo < 12) score += 10;

  // Topic volume bonus: more articles on same topic = trending
  const vol = feedMeta.recent_volume || 0;
  if (vol > 20) score += 15;
  else if (vol > 10) score += 10;
  else if (vol > 5) score += 5;

  // Title signals: breaking news indicators
  const title = String(item.json.title || '').toLowerCase();
  const hotWords = ['urgente', 'breaking', 'exclusivo', 'alerta', 'novo', 'lança', 'anuncia', 'revela'];
  if (hotWords.some(w => title.includes(w))) score += 10;

  return Math.min(score, 100);
}

const feedItem = $('Build Feed List').item.json;
const output = [];

for (const item of items) {
  try {
    const title = String(item.json.title || '').trim();
    const link = String(item.json.link || '').trim();
    if (!title || !link) continue;
    const fingerprint = fnv1aHash(title.toLowerCase().replace(/[^a-z0-9]/g, ''));
    const trendScore = calculateTrendScore(item, feedItem);

    output.push({
      json: {
        title: title,
        summary: String(item.json.contentSnippet || item.json.content || '').substring(0, 500),
        canonical_url: link,
        source_name: String(item.json.creator || item.json.source || 'Google News'),
        topic: feedItem.topic || 'geral',
        published_at: item.json.isoDate || item.json.pubDate || new Date().toISOString(),
        source_url: feedItem.url,
        duplicate_fingerprint: fingerprint,
        processed: false,
        content: null,
        trend_score: trendScore,
        search_volume: feedItem.recent_volume || 0,
        trend_velocity: 0,
        metadata: {
          feed_url: feedItem.url,
          search_tag: feedItem.search_tag,
          trend_score: trendScore
        }
      }
    });
  } catch (e) { /* skip */ }
}

// Sort by trend score descending - prioritize trending content
output.sort((a, b) => (b.json.trend_score || 0) - (a.json.trend_score || 0));

return output;
